#include <bits/stdc++.h>
using namespace std;
const int maxn=1001*1001;
int a,n;
int ans[maxn+5],nearest=1001*1001;
int main(){
    cin>>a>>n;
    for(int i=ceil(sqrt(double(a)));i*i<=maxn;i++)
        for(int j=1;j*i*i<=maxn;j++)
            ans[j*i*i]=j*i*i;
    for(int i=maxn;i>0;i--){
        if(ans[i]==i)nearest=i;
        else ans[i]=nearest;
    }
    for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        if(ans[x]==x)cout<<"lucky\n";
        else cout<<ans[x]<<endl;
    }
    return 0;
}
